#include<iostream>
#include<cmath>
using namespace std;
int main()
{
	double aj,bj,as,bs,az,bz=0;
	int n,k;
	cin>>n>>k;
	for(int i=1;i<=n;i++){
		if(i%k==0){
			as+=1;
			az+=i;
		}
		else{
			bs+=1;
			bz+=i;
		}
	}
	aj=az/as;
	bj=bz/bs;
	printf("%.1f",aj);
	cout<<" ";
	printf("%.1f",bj);
    return 0;
}
